INSERT INTO parrot_species
(id, name, english_name, origin, size, avg_lifespan, habits, difficulty, image, status, create_time, update_time)
VALUES
(1, '虎皮鹦鹉', 'Budgerigar', '澳大利亚', '小型', '7-10年', '虎皮鹦鹉资料参考公开物种库整理，学名为 Melopsittacus undulatus。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '入门', 'https://upload.wikimedia.org/wikipedia/commons/5/5d/189_Red-and-green_macaw_couple_flying_in_Chapada_dos_Guimar%C3%A3es_National_Park_Photo_by_Giles_Laurent.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(2, '玄凤鹦鹉', 'Cockatiel', '澳大利亚', '中小型', '10-15年', '玄凤鹦鹉资料参考公开物种库整理，学名为 Nymphicus hollandicus。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '入门', 'https://upload.wikimedia.org/wikipedia/commons/a/a7/Hyacinth_macaw_%28Anodorhynchus_hyacinthinus%29_head.JPG', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(3, '和尚鹦鹉', 'Monk Parakeet', '南美洲', '中型', '15-20年', '和尚鹦鹉资料参考公开物种库整理，学名为 Myiopsitta monachus。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '中等', 'https://upload.wikimedia.org/wikipedia/commons/c/ce/Macaw_parrot_sitting_on_a_tree_branch.jpg_.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(4, '牡丹鹦鹉', 'Lovebird', '非洲西南部', '小型', '10-15年', '牡丹鹦鹉资料参考公开物种库整理，学名为 Agapornis roseicollis。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '中等', 'https://upload.wikimedia.org/wikipedia/commons/4/42/Red-and-green_macaw_%28Ara_chloropterus%29_juvenile.JPG', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(5, '金刚鹦鹉', 'Macaw', '中南美洲', '大型', '40-60年', '金刚鹦鹉资料参考公开物种库整理，学名为 Ara ararauna。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '较难', 'https://upload.wikimedia.org/wikipedia/commons/7/7c/A_budgerigar_in_Shiraz.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(6, '葵花凤头鹦鹉', 'Sulphur-crested Cockatoo', '澳大利亚、新几内亚', '大型', '40-70年', '葵花凤头鹦鹉资料参考公开物种库整理，学名为 Cacatua galerita。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '较难', 'https://upload.wikimedia.org/wikipedia/commons/0/0f/Blue_Parrot_on_the_cage.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(7, '亚马逊鹦鹉', 'Amazon Parrot', '南美洲', '中大型', '30-50年', '亚马逊鹦鹉资料参考公开物种库整理，学名为 Amazona aestiva。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '较难', 'https://upload.wikimedia.org/wikipedia/commons/8/8c/Budgerigar_by_Bipro.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(8, '折衷鹦鹉', 'Eclectus Parrot', '新几内亚、澳大利亚东北部', '中大型', '30-40年', '折衷鹦鹉资料参考公开物种库整理，学名为 Eclectus roratus。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '中等', 'https://upload.wikimedia.org/wikipedia/commons/a/a1/Green_budgerigar_parrot_in_mongolia%282%29.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(9, '灰鹦鹉', 'African Grey Parrot', '非洲中西部', '中型', '40-60年', '灰鹦鹉资料参考公开物种库整理，学名为 Psittacus erithacus。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '较难', 'https://upload.wikimedia.org/wikipedia/commons/4/43/Green_budgerigar_parrot_in_mongolia.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(10, '小太阳鹦鹉', 'Sun Parakeet', '南美洲东北部', '中小型', '20-30年', '小太阳鹦鹉资料参考公开物种库整理，学名为 Aratinga solstitialis。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '中等', 'https://upload.wikimedia.org/wikipedia/commons/d/d9/Parrot_yellow.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(11, '凯克鹦鹉', 'Caique', '南美洲北部', '中型', '25-35年', '凯克鹦鹉资料参考公开物种库整理，学名为 Pionites melanocephalus。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '中等', 'https://upload.wikimedia.org/wikipedia/commons/2/2f/Nymphicus_hollandicus_-_Forst_01.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(12, '塞内加尔鹦鹉', 'Senegal Parrot', '西非', '中小型', '25-30年', '塞内加尔鹦鹉资料参考公开物种库整理，学名为 Poicephalus senegalus。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '中等', 'https://upload.wikimedia.org/wikipedia/commons/2/2d/Nymphicus_hollandicus_-perching_on_wires_-Australia-6a.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(13, '红领绿鹦鹉', 'Rose-ringed Parakeet', '非洲、南亚', '中型', '20-30年', '红领绿鹦鹉资料参考公开物种库整理，学名为 Psittacula krameri。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '中等', 'https://upload.wikimedia.org/wikipedia/commons/3/39/Nymphicus_hollandicus_162198224.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(14, '绯胸鹦鹉', 'Red-breasted Parakeet', '南亚、东南亚', '中型', '20-25年', '绯胸鹦鹉资料参考公开物种库整理，学名为 Psittacula alexandri。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '中等', 'https://upload.wikimedia.org/wikipedia/commons/b/b7/Nymphicus_hollandicus_Karratha_12.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(15, '红额鹦鹉', 'Kakariki', '新西兰', '小型', '10-15年', '红额鹦鹉资料参考公开物种库整理，学名为 Cyanoramphus novaezelandiae。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '入门', 'https://upload.wikimedia.org/wikipedia/commons/7/76/Nymphicus_hollandicus_Karratha_3.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00'),
(16, '紫蓝金刚鹦鹉', 'Hyacinth Macaw', '巴西、玻利维亚、巴拉圭', '大型', '50-70年', '紫蓝金刚鹦鹉资料参考公开物种库整理，学名为 Anodorhynchus hyacinthinus。日常活动需要稳定光照、清洁饮水和适量互动，饲养时要注意噪声、啃咬和换羽期观察。', '较难', 'https://upload.wikimedia.org/wikipedia/commons/1/18/Nymphicus_hollandicus_Karratha_5.jpg', 1, '2026-06-30 08:20:00', '2026-06-30 08:20:00');
