(1, 'PAR-2026-001', '墨芽', 1, '雌性', 7, '2018-12-22', '蓝白', 'https://upload.wikimedia.org/wikipedia/commons/0/0f/Blue_Parrot_on_the_cage.jpg', '正常', '救助转入', '2026-04-07', '亲人稳定，对熟悉的饲养员反应较好。', '训练前先给适应时间，避免突然靠近。', '在园', '墨芽是园区登记的虎皮鹦鹉，适合用于档案、预约和养护记录演示。', 0, '2026-06-30 08:40:00', '2026-06-30 08:40:00'),
(2, 'PAR-2026-002', '墨云', 2, '雄性', 11, '2015-03-22', '红绿', 'https://upload.wikimedia.org/wikipedia/commons/8/8c/Budgerigar_by_Bipro.jpg', '正常', '合作机构转入', '2026-04-30', '亲人稳定，对熟悉的饲养员反应较好。', '训练前先给适应时间，避免突然靠近。', '在园', '墨云是园区登记的玄凤鹦鹉，适合用于档案、预约和养护记录演示。', 1, '2026-06-30 08:40:00', '2026-06-30 08:40:00'),
(3, 'PAR-2026-003', '豆橙', 3, '未知', 10, '2015-10-16', '绿色', 'https://upload.wikimedia.org/wikipedia/commons/a/a1/Green_budgerigar_parrot_in_mongolia%282%29.jpg', '正常', '救助转入', '2025-03-07', '亲人稳定，对熟悉的饲养员反应较好。', '保持笼舍干燥，每日更换饮水。', '在园', '豆橙是园区登记的和尚鹦鹉，适合用于档案、预约和养护记录演示。', 1, '2026-06-30 08:40:00', '2026-06-30 08:40:00'),
(4, 'PAR-2026-004', '安木', 4, '雌性', 4, '2022-03-13', '绿色', 'https://upload.wikimedia.org/wikipedia/commons/4/43/Green_budgerigar_parrot_in_mongolia.jpg', '正常', '外部引进', '2025-08-19', '比较谨慎，对熟悉的饲养员反应较好。', '训练前先给适应时间，避免突然靠近。', '在园', '安木是园区登记的牡丹鹦鹉，适合用于档案、预约和养护记录演示。', 1, '2026-06-30 08:40:00', '2026-06-30 08:40:00'),
(5, 'PAR-2026-005', '星木', 5, '雄性', 4, '2021-11-05', '深蓝', 'https://upload.wikimedia.org/wikipedia/commons/d/d9/Parrot_yellow.jpg', '正常', '救助转入', '2024-05-15', '比较谨慎，对熟悉的饲养员反应较好。', '训练前先给适应时间，避免突然靠近。', '在园', '星木是园区登记的金刚鹦鹉，适合用于档案、预约和养护记录演示。', 0, '2026-06-30 08:40:00', '2026-06-30 08:40:00'),
(6, 'PAR-2026-006', '星团', 6, '未知', 11, '2015-01-18', '橙黄', 'https://upload.wikimedia.org/wikipedia/commons/2/2f/Nymphicus_hollandicus_-_Forst_01.jpg', '正常', '园区繁育', '2026-05-16', '安静温顺，对熟悉的饲养员反应较好。', '训练前先给适应时间，避免突然靠近。', '在园', '星团是园区登记的葵花凤头鹦鹉，适合用于档案、预约和养护记录演示。', 1, '2026-06-30 08:40:00', '2026-06-30 08:40:00'),
