INSERT INTO notice
(id, title, content, type, cover_image, publish_status, publish_time, creator_id, create_time, update_time)
VALUES
(1, '园区开放预约咨询服务', '客户可在前台选择公开展示的鹦鹉并提交咨询预约，工作人员会在后台统一处理。', '系统公告', 'https://upload.wikimedia.org/wikipedia/commons/4/42/Red-and-green_macaw_%28Ara_chloropterus%29_juvenile.JPG', '已发布', '2026-06-21 09:00:00', NULL, '2026-06-30 08:00:00', '2026-06-30 08:00:00'),
(2, '换羽期的基础照护建议', '换羽期要保持环境安静，注意补充新鲜蔬果和干净饮水，并持续观察精神状态。', '饲养知识', 'https://upload.wikimedia.org/wikipedia/commons/7/7c/A_budgerigar_in_Shiraz.jpg', '已发布', '2026-06-22 09:00:00', NULL, '2026-06-30 08:00:00', '2026-06-30 08:00:00'),
(3, '新鹦鹉入园后的隔离观察', '新入园个体建议先进行隔离观察，记录体重、食欲和粪便情况，再逐步安排展示。', '饲养知识', 'https://upload.wikimedia.org/wikipedia/commons/0/0f/Blue_Parrot_on_the_cage.jpg', '已发布', '2026-06-23 09:00:00', NULL, '2026-06-30 08:00:00', '2026-06-30 08:00:00'),
(4, '夏季笼舍通风提醒', '高温天气要注意通风降温，避免阳光长时间直晒，同时保持饮水清洁。', '系统公告', 'https://upload.wikimedia.org/wikipedia/commons/8/8c/Budgerigar_by_Bipro.jpg', '已发布', '2026-06-24 09:00:00', NULL, '2026-06-30 08:00:00', '2026-06-30 08:00:00'),
(5, '训练时长不宜过长', '单次训练建议控制在十到三十分钟内，以正向奖励为主，避免强迫互动。', '饲养知识', 'https://upload.wikimedia.org/wikipedia/commons/a/a1/Green_budgerigar_parrot_in_mongolia%282%29.jpg', '已发布', '2026-06-25 09:00:00', NULL, '2026-06-30 08:00:00', '2026-06-30 08:00:00'),
(6, '预约咨询材料准备', '客户预约前可先准备家庭环境、饲养经验和期望互动方式，便于工作人员给出建议。', '系统公告', 'https://upload.wikimedia.org/wikipedia/commons/4/43/Green_budgerigar_parrot_in_mongolia.jpg', '已发布', '2026-06-26 09:00:00', NULL, '2026-06-30 08:00:00', '2026-06-30 08:00:00'),
(7, '治疗中个体暂不开放展示', '处于治疗中或观察中的鹦鹉暂不开放前台预约，以保证动物福利和客户安全。', '系统公告', 'https://upload.wikimedia.org/wikipedia/commons/d/d9/Parrot_yellow.jpg', '已发布', '2026-06-27 09:00:00', NULL, '2026-06-30 08:00:00', '2026-06-30 08:00:00'),
(8, '后台演示用未发布公告', '这条公告用于演示未发布状态，前台公开列表中不会显示。', '系统公告', 'https://upload.wikimedia.org/wikipedia/commons/2/2f/Nymphicus_hollandicus_-_Forst_01.jpg', '未发布', NULL, NULL, '2026-06-30 08:00:00', '2026-06-30 08:00:00');
